import{B as e,Q as t,s as n,z as r}from"./chunks/framework.BtoUXlJN.js";var i=JSON.parse(`{"title":"Wrestler Profile","description":"","frontmatter":{},"headers":[],"relativePath":"guide/wrestler-profile.md","filePath":"guide/wrestler-profile.md"}`),a={name:`guide/wrestler-profile.md`};function o(n,i,a,o,s,c){return t(),r(`div`,null,[...i[0]||=[e(`<h1 id="wrestler-profile" tabindex="-1">Wrestler Profile <a class="header-anchor" href="#wrestler-profile" aria-label="Permalink to &quot;Wrestler Profile&quot;">​</a></h1><p>Welcome to the Wrestler Profile guide. This documentation is automatically generated from the latest game features.</p><h2 id="modernized-wrestler-dashboard" tabindex="-1">Modernized Wrestler Dashboard <a class="header-anchor" href="#modernized-wrestler-dashboard" aria-label="Permalink to &quot;Modernized Wrestler Dashboard&quot;">​</a></h2><p>The redesigned wrestler profile features a prominent &#39;Hero&#39; section with the wrestler&#39;s image, biography, and personal relationships always visible. Secondary information is organized into a clean, mobile-friendly accordion layout.</p><p><img src="/atw-rpg/docs/screenshots/wrestler-profile-redesign.png" alt="Modernized Wrestler Dashboard"></p><hr><h2 id="personal-relationships" tabindex="-1">Personal Relationships <a class="header-anchor" href="#personal-relationships" aria-label="Permalink to &quot;Personal Relationships&quot;">​</a></h2><p>Wrestler profiles now include a &#39;Relationships&#39; section showing their social connections. These bonds provide chemistry bonuses when related wrestlers perform together.</p><p><img src="/atw-rpg/docs/screenshots/wrestler-profile-relationships.png" alt="Personal Relationships"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="championship-title-history" tabindex="-1">Championship Title History <a class="header-anchor" href="#championship-title-history" aria-label="Permalink to &quot;Championship Title History&quot;">​</a></h3><p>The show detail view opens — you can review the full card and segment results from the night the title changed hands. All segments, participants, and AI-generated narration are preserved in the show record.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/wrestler-title-history.mp4" type="video/mp4"></video><hr><h3 id="recent-match-log" tabindex="-1">Recent Match Log <a class="header-anchor" href="#recent-match-log" aria-label="Permalink to &quot;Recent Match Log&quot;">​</a></h3><p>Click the show name in any row to navigate directly to that show&#39;s detail view. From there you can review the full card, narration, and results for every segment on the night the match took place.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/wrestler-recent-matches.mp4" type="video/mp4"></video><hr><h3 id="feud-and-rivalry-history" tabindex="-1">Feud and Rivalry History <a class="header-anchor" href="#feud-and-rivalry-history" aria-label="Permalink to &quot;Feud and Rivalry History&quot;">​</a></h3><p>Heat accumulates automatically from match outcomes, drama events, and promos. Booking a high-heat feud match on a big show accelerates the rise while keeping them apart lets the heat decay naturally over time.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/wrestler-feud-history.mp4" type="video/mp4"></video><hr>`,23)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};